#include<bits/stdc++.h>
using namespace std;
unsigned int maxval,n,m,cnt;
struct node1
{
    unsigned int l,r,lson,rson;
    unsigned int sum;
    unsigned int tag;
}a[60000010];
stack<unsigned int> s;
struct sum_segment_tree
{
    unsigned int root;
    sum_segment_tree():root(0){}
    void pushadd(unsigned int x,unsigned int v)
    {
        a[x].sum+=(a[x].r-a[x].l+1)*v;
        a[x].tag+=v;
    }
    void pushdown(unsigned int x)
    {
        unsigned int l=a[x].l,r=a[x].r;
        unsigned int mid=(l+r)>>1;
        if(!a[x].lson)
        {
            a[x].lson=newnode(l,mid,0);
        }
        pushadd(a[x].lson,a[x].tag);
        if(!a[x].rson)
        {
            a[x].rson=newnode(mid+1,r,0);
        }
        pushadd(a[x].rson,a[x].tag);
        a[x].tag=0;
    }
    unsigned int newnode(unsigned int l,unsigned int r,unsigned int v)
    {
        unsigned int x=0;
        // if(!s.empty())
        // {
        //     x=s.top();
        //     s.pop();
        // }
        // else
        // {
            x=++cnt;
        // }
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        a[x].sum=v;
        a[x].lson=a[x].rson=0;
        return x;
    }
    void add1(unsigned int &x,unsigned int l,unsigned int r,unsigned int v,int newl=-1,int newr=-1)
    {
        if(newl==-1)
        {
            newl=1;
        }
        if(newr==-1)
        {
            newr=maxval;
        }
        if(x==0)
        {
            x=newnode(newl,newr,0);
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].tag+=v;
            a[x].sum+=(a[x].r-a[x].l+1)*v;
            return;
        }
        pushdown(x);
        unsigned int mid=(a[x].l+a[x].r)>>1;
        a[x].sum+=(min(a[x].r,r)-max(a[x].l,l)+1)*v;
        if(l<=mid)
        {
            add1(a[x].lson,l,r,v,newl,mid);
        }
        if(r>mid)
        {
            add1(a[x].rson,l,r,v,mid+1,newr);
        }
    }
    void add(unsigned int l,unsigned int r,unsigned int v)
    {
        add1(root,l,r,v);
    }
    unsigned int getsum1(unsigned int &x,unsigned int l,unsigned int r,int newl=-1,int newr=-1)
    {
        if(newl==-1)
        {
            newl=1;
        }
        if(newr==-1)
        {
            newr=maxval;
        }
        if(x==0)
        {
            x=newnode(newl,newr,0);
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        unsigned int mid=(a[x].l+a[x].r)>>1;
        unsigned int ans=0;
        if(l<=mid)
        {
            ans+=getsum1(a[x].lson,l,r,newl,mid);
        }
        if(r>mid)
        {
            ans+=getsum1(a[x].rson,l,r,mid+1,newr);
        }
        return ans;
    }
    unsigned int getsum(unsigned int l,unsigned int r)
    {
        return getsum1(root,l,r);
    }
    void del(unsigned int x=-1)
    {
        if(x==-1)
        {
            x=root;
        }
        a[x].sum=0;
        if(a[x].l==a[x].r)
        {
            a[x].l=a[x].r=0;
            s.push(x);
            return;
        }
        a[x].l=a[x].r=0;
        del(a[x].lson);
        del(a[x].rson);
        a[x].lson=a[x].rson=0;
        s.push(x);
    }
};
struct segment_tree
{
    struct node1
    {
        unsigned int l,r,lson,rson;
        sum_segment_tree sum;
    }a[6000010];
    unsigned int cnt1,root;
    segment_tree():cnt1(0),root(0){}
    unsigned int newnode(unsigned int l,unsigned int r)
    {
        unsigned int x=++cnt1;
        a[x].l=l;
        a[x].r=r;
        a[x].sum.root=0;
        a[x].lson=a[x].rson=0;
        return x;
    }
    void add1(unsigned int &x,unsigned int p,unsigned int L,unsigned int R,unsigned int V,int newl=-1,int newr=-1)
    {
        if(newl==-1)
        {
            newl=1;
        }
        if(newr==-1)
        {
            newr=maxval;
        }
        if(x==0)
        {
            x=newnode(newl,newr);
        }
        unsigned int mid=(a[x].l+a[x].r)>>1;
        a[x].sum.add(L,R,V);
        if(a[x].l==a[x].r)
        {
            return;
        }
        if(p<=mid)
        {
            add1(a[x].lson,p,L,R,V,newl,mid);
        }
        else
        {
            add1(a[x].rson,p,L,R,V,mid+1,newr);
        }
    }
    void add(unsigned int p,unsigned int l,unsigned int r,unsigned int v)
    {
        add1(root,p,l,r,v);
    }
    unsigned int query(unsigned int &x,unsigned int l,unsigned int r,unsigned int k,int newl=-1,int newr=-1)
    {
        if(newl==-1)
        {
            newl=1;
        }
        if(newr==-1)
        {
            newr=maxval;
        }
        if(x==0)
        {
            x=newnode(newl,newr);
        }
        if(a[x].l==a[x].r)
        {
            return a[x].l;
        }
        unsigned int mid=(a[x].l+a[x].r)>>1;
        unsigned int ans=0,tmp=0;
        if(a[x].rson)
        {
            tmp=a[a[x].rson].sum.getsum(l,r);
        }
        if(k<=tmp)
        {
            return query(a[x].rson,l,r,k,mid+1,newr);
        }
        else
        {
            return query(a[x].lson,l,r,k-tmp,newl,mid);
        }
    }
}t;
int main()
{
    scanf("%u%u",&n,&m);
    maxval=n*2+5;
    while(m--)
    {
        unsigned int op,l,r;
        long long c;
        scanf("%u%u%u%lld",&op,&l,&r,&c);
        if(op==1)
        {
            c+=(int)(n)+1;
            t.add(c,l,r,1);
        }
        else
        {
            // int ans=(int)(t.query(t.root,l,r,c))-(int)(n)-1;
            printf("%d\n",(int)(t.query(t.root,l,r,c))-(int)(n)-1);
        }
    }
    return 0;
}
